INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('66be1794-f21f-c6a5-a544-e3b3f1ff8438', 'CHL-00000004', '20611673', 'HDI Seguros', 'Alvaro Fabian', 'Gonzalez Cortes', '13333172-7', 'alvarofgc@gmail.com', '9 5523 8439', '9 5523 8439', 'Calle Garay Edif El Canelo N°1189 Depto. N° 43', 'Chile', 'Valparaíso', 'Marga Marga', 'Villa Alemana', 'Property', 'closed', 'Rotura de cañerías', 'Por medio del presente informo un siniestro ocurrido en mi departamento, consistente en una filtración de agua proveniente de una cañería interior. El evento se inicia cuando una cañería comienza a emitir un ruido fuerte y anormal, tras lo cual se detecta goteo y filtración de agua en el sector de la cocina. Posteriormente, la humedad y el paso de agua se evidencian también en la habitación más pequeña del departamento, la cual colinda directamente con la cocina y comparte una pared de material ligero. Debido a esta condición constructiva, el agua se filtra a través del muro común, afectando tanto la pared de la cocina como la pared de la habitación contigua, generando daños por humedad. El origen del daño corresponde a una cañería interior del departamento, no atribuible a terceros ni a filtraciones externas.;', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Calle Garay Edif El Canelo N°1189 Depto.N° 43', 'alvarofgc@gmail.com', '1957951', 'CHL.213869', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-01-02', '2026-01-05', '2026-01-06');
