INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('1d323af2-6960-9378-d831-2da49ab2faf1', 'CHL-00000006', '20611673', 'HDI Seguros', 'Ana Maria', 'Quezada Sepulveda', '14514348-9', 'contacto@asesoresprime.com', '9 4245 3445', '9 4245 3445', 'Calle Flor De Lis N° 523', 'Chile', 'Maule', 'Talca', 'Talca', 'Property', 'closed', 'Rotura de cañerías', 'El siniestro es una rotura de cañería ocurrida en el piso de la bodega lateral de la vivienda, la cual produce daños tanto por alcance de humedad como por trabajos de reparaciones del siniestro.;', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', '', '', '1958102', 'CHL.213871', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2025-12-23', '2026-01-05', '2026-01-06');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('cfcfea86-8348-399b-272b-9eeccc57a14d', 'CHL-00000007', '20606674', 'HDI Seguros', 'María Angelica', 'Meza Hernández', '8003577-2', 'angelicamezah@gmail.com', '9 3394 0350', '9 3394 0350', 'Avenida Perú N° 653 Depto N° 906', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Recoleta', 'Property', 'closed', 'Rotura de cañerías', 'Por problema de la bomba de agua del edificio, hubo un corte de agua desde la noche del 31 de diciembre a la mañana del 1 de enero. Yo me encontraba fuera de mi dpto. durante las horas que los técnicos arreglaron el desperfecto y dieron nuevamente el agua. La llave de mi lavaplatos tenía un desperfecto porque una vez la pasé a llevar y tenía una pequeña fuga de agua. A la media tarde del 1 de enero, me llamaron para avisarme que mi depto. estaba inundado, y que caía agua al depto. de abajo. Cuando llegué a mi dpto habían cortado el agua del medidor para evitar más daños y pude ver que la causa era que la llave del lavaplatos se había salido de la base por la presión del agua, razón por la cual estaba inundada la cocina, la loggia, parte del living, del dormitorio pequeño y del escritorio. Asimismo había daños varios en el depto. de abajo por el agua que cayó.', 'NO', 'NO', 'N/A', '', '', '', '', '', '', '', '1958109', 'CHL.213878', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-01-01', '2026-01-02', '2026-01-06');
