INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('bbdca2a2-c49b-cc9d-b695-55b77c545c12', 'CHL-00000027', '20611673', 'HDI Seguros', 'Susanli Mariluz', 'Medina Andrade', '15758213-5', 'susanlimedina@gmail.com', '', '9 7125 6744', 'Camino Lago Atravesado, Km 3,5, Callejón Luna s/n', 'Chile', 'Aysén del General Carlos Ibáñez del Campo', 'Coyhaique', 'Coyhaique', 'Property', 'closed', 'Rotura de cañerías', 'El día 12-01-2026 salí durante la mañana , al regresar pasadas las 18:00 hrs me encontré con agua en la habitación principal que pasaba al dormitorio de en frente , al ver de donde salia el agua me doy cuenta que hay una rotura en la cañeria del lavamanos del baño en suite del dormitorio, la cual filtraba agua con alta presión , procedí a cortar el agua y a secar los dormitorios y el baño, viendo como se deterioró piso flotante , zapatos, alfombras y todo lo que tuvo contacto con el agua, que por el nivel en la cual encontramos la casa debe haber ocurrido desde muy temprano ya que todo estaba totalmente inundado.;', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Susanli Mariluz Medina Andrade', 'susanlimedina@gmail.com', '1958787', 'CHL.213996', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-01-12', '2026-01-15', '2026-01-15');
