INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('912a5958-30b7-02b8-2b67-a45912f9047e', 'CHL-00000056', '20618001', 'HDI Seguros', 'Ilan Israel Alberto', 'Numhauser Kreutzberger', '16432373-0', 'ilan.numhauser@me.com', '', '9 5228 7878', 'Camino Las Flores N° 10800 C', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Las Condes', 'Property', 'closed', 'Rotura de cañerías', 'Se produjo la rotura de una cañería de agua en la cocina del inmueble, lo que generó una filtración de agua no visible de forma inmediata. Como consecuencia, la humedad afectó de manera severa los muebles de cocina de madera, los cuales se encuentran fijos al inmueble, provocando hinchazón, deterioro estructural y pudrición, quedando sin posibilidad de reparación y debiendo ser reemplazados. El daño fue detectado una vez que se evidenciaron los efectos de la filtración. Se procedió a cortar el suministro de agua y mitigar la causa del daño', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Ilan Israel Alberto Numhauser', 'ilan.numhauser@me.com', '1959447', 'CHL.214176', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-01-18', '2026-01-27', '2026-01-28');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('16c7fc3f-61a4-505e-0a14-5ffbe50dd687', 'CHL-00000057', '20611673', 'HDI Seguros', 'Carla Carolyn', 'Stuardo Lespay', '10916170-5', 'carlacarolyns2@gmail.com', '', '9 7977 0960', 'Camilo Henriquez  N° 2247 Depto N°209 Est 17', 'Chile', 'Biobío', 'Concepción', 'Concepción', 'Property', 'closed', 'Rotura de cañerías', 'Se observa que agua de wc principal sigue corriendo, se trata de cortar a traves de llave de paso directo y no corta, donde ademas de corta dedes el baño principal, tampoco corta, lo que hy que hacerlo desde el medidor general del depto, ademas de observo que desde el baño servicio, esta filtrando al piso inferior que esta produciendo daño en recubrimiento. necesito con urgencia pasos a seguir.;', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Carla Carolyn Stuardo Lespay', 'carlacarolyns2@gmail.com', '1959468', 'CHL.214177', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-01-14', '2026-01-27', '2026-01-27');
