INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('512504fc-4de4-611f-9362-2d3ab95624da', 'CHL-00000125', '20611673', 'HDI Seguros', 'Francisco Javier', 'Castro Jorquera', '17313983-7', 'fcofic@gmail.com', '', '9 9301 3508', 'Calle Santa Victoria N° 492 Depto. N°205', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Santiago', 'Property', 'closed', 'No informado', 'Desde el 2023 tengo problemas con el baño del departamento, ya que sube espuma y agua desde la taza del baño, la tina y ahora último del lava mano. Esto lo reporté a los administradores del edificio, lamentablemente estos han cambiado al menos 4 veces. Han hecho limpieza de los ductos horizontales y verticales pero el problema persistió. El año 2025 le pidieron a una empresa externa que hiciera la evaluación de la situación, la cual entrego un informe señalando: que el problema era estructural y que no se puede intervenir porque esto podría afectar al resto del edificio. Sin embargo, la situación es insalubre y sigue repitiéndose al menos 3 veces por semana.', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Francisco Javier Castro Jorquera', 'fcofic@gmail.com', '1960651', 'CHL.214545', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-02-06', '2026-02-11', '2026-02-11');
