INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('23c162fb-6bfd-3e5e-10a2-44014ea81687', 'CHL-00000207', '20611673', 'HDI Seguros', 'Alejandro Jose', 'Rivera Fernandez', '10311052-1', 'paorosenthal@hotmail.com', '', '9 5623 6744', 'Calle Camino Del Sol 4450 Casa 5', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Lo Barnechea', 'Property', 'closed', 'Rotura de cañerías', 'Se mojo un muro de un dormitorio del subterraneo y se miro el medidor de agua que corria rapido con todas las llaves de agua cerradas. Llamamos a deteccion de fugas y con sus instrumentos detectaron una rotura de cañeria en la cocina en el lugar donde va el refrigerador, debajo a una profundidad bastante grande se encontró. Procedieron a reparar la fuga de agua en la cañería. Ahora hay que tapar ese agujero profundo ya que el equipo de fuga no hace ese trabajo. Tengo que llamar a un maestro para que tape ese agujero y reparar el muro del dormitorio afectado que se mojó por la rotura de cañeria arriba que queda arriba de este.;', 'NO', 'NO', 'n/a', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Alejandro Jose Rivera Fernandez', 'paorosenthal@hotmail.com', '1962760', 'CHL.215064', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-02-27', '2026-03-09', '2026-03-09');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('e829d191-cd58-6e5a-da1f-a62b7a519e17', 'CHL-00000208', '20611673', 'HDI Seguros', 'Ricardo Alfonso', 'Villa Barrios', '26134794-6', 'ricardoa.villab@gmail.com', '', '9 2600 1228', 'Pasaje Puelche N ° 755', 'Chile', 'Los Lagos', 'Llanquihue', 'Llanquihue', 'Property', 'closed', 'Viento y Lluvia', 'Por lluvia intensa comenzo a filtrarse el agua por el techo del quincho, dañando una pared de mi pieza en el piso 2, abajo se comunica con la entrada del quincho, y habian 2 goteas que empezaron a gotaer mucho y dañaron la esquina del chincho y la campana de la parillera', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Ricardo Alfonso Villa Barrios', 'ricardoa.villab@gmail.com', '1962765', 'CHL.215065', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-03-01', '2026-03-09', '2026-03-09');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('ab8cb686-8081-9348-f995-de4983975fc3', 'CHL-00000209', '20621072', 'HDI Seguros', 'Carmen', 'Polanco', '7291530-5', 'clpolanco2013@gmail.com', '', '9 8827 7678', 'Avda. El Remanso 11110 casa 26 B', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Las Condes', 'Property', 'closed', 'Viento y Lluvia', 'Al abrir la bodega para ir a buscar una maleta nos dimos cuenta que el cielo había roto en la zona donde esta la luminaria, escurriendo agua hacia el interior. Revisado
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('13f3424f-0eeb-da19-5ab0-906edc1609a3', 'CHL-00000210', '20598798', 'HDI Seguros', 'Inversiones Los Navegantes Limitada', '', '76099719-6', 'berni.heusser@gmail.com', '', '9 7985 2851', 'Arenales 156 Casa 82', 'Chile', 'Valparaíso', 'Valparaíso', 'Concón', 'Property', 'closed', 'Incendio', 'El día 3 de enero del presente año, se produjo un pequeño incendio de origen eléctrico en el tablero eléctrico del departamento. El evento generó calor y daño en la barra repartidora tetrapolar, la cual se derritió parcialmente. Debido a esto fue necesario reemplazar la barra tetrapolar y los cables que resultaron afectados por el calor y el daño eléctrico, para restablecer el funcionamiento seguro de la instalación', 'NO', 'NO', 'N/A', '', '', '', '', '', 'Juan Heusser Risopatron', 'berni.heusser@gmail.com', '1962779', 'CHL.215067', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-01-03', '2026-03-09', '2026-03-09');
