INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('e72b6733-e772-1540-442f-f5c3dbac8732', 'CHL-00000212', '20611673', 'HDI Seguros', 'Ada Maria', 'Diaz Espinosa', '14018348-2', 'jeperez@uc.cl', '', '9 5104 5177', 'Calle Pinares De Montemar 467', 'Chile', 'Valparaíso', 'Valparaíso', 'Concón', 'Property', 'closed', 'Rotura de cañerías', 'Durante la mañana del día domingo 08/03/2026 comenzó la filtración de  agua desde la losa de concreto que separa el primer y segundo piso del inmueble asegurado. Producto de una rotura de cañería interior, produciendo el anegamiento del departamento del primer piso  con observacion del piso nivel por humedad y del cielo del otro primer nivel.', 'NO', 'NO', 'n/a', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Ada Maria Diaz Espinosa', 'jeperez@uc.cl', '1962878', 'CHL.215069', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-03-08', '2026-03-10', '2026-03-10');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('84d1836f-66bf-73ad-139f-a5dc89fc2c79', 'CHL-00000213', '251066', 'HDI Seguros', 'Bellavista S.A De Inversiones', '', '96534180-3', 'fdib@destapas.cl', '', '9 8529 6715', 'Calle N° 5 Norte N° 231', 'Chile', 'Valparaíso', 'Valparaíso', 'Viña del Mar', 'Property', 'in_review', 'Robo con Fuerza en las cosas', 'El Lunes 23 febrero a eso de las 4 de la madrugada 2 sujetos ingresaron a nuestro local (Destapas Beer House). Dentro de su intento de ingreso (el cual lograron) rompieron varios ventanales y forzaron varias cerraduras rompiéndolas. Dentro de lo que robaron fueron todos nuestros licores y parte de nuestras bebidas, 1 parlante marca bose portátil, una tablet de caja y una cámara de seguridad instalada en la puerta de cocina. Un remo de acero inoxidable en cocina', 'NO', 'NO', 'n/a', 'ARTHUR J. GALLAGHER CORREDORES DE SEGUROS SPA', '', '', '', '', 'Bellavista S.A De Inversiones', 'fdib@destapas.cl', '1022153', 'CHL.215070', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-02-23', '2026-03-10', '2026-03-10');
