INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('6d8a949b-3fd4-2136-efd6-3d97c4771278', 'CHL-00000216', '20611878', 'HDI Seguros', 'Inversiones A & M Ltda', '', '76049228-0', 'aecookc@gmail.com', '', '', 'Av/ Las Arañas Interior,2313', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'La Reina', 'Property', 'closed', 'Rotura Accidental de Cristales', 'Habiendo escuchado un golpe la tarde anterior, revisamos al día siguiente en la mañana y nos encontramos con el ventanal principal del living de la casa dañado en su hoja exterior (termopanel).  A pocos metros encontramos una pelota de hockey, aunque no tenemos certeza que haya sido eso el causante del daño.', 'NO', 'NO', 'N/A', 'PRIME CORREDORES DE SEGUROS SPA', '', '', '', '', 'Anthony Cook Cooper', 'aecookc@gmail.com', '1962893', 'CHL.215073', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-03-05', '2026-03-10', '2026-03-10');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('7e91d4ae-e777-f4d2-c3b3-33cf69c0e8b2', 'CHL-00000217', '20611673', 'HDI Seguros', 'Maria Silveria', 'Millao Flores', '10477812-7', 'maria.millaof@gmail.com', '', '9 7214 6027', 'Calle Lugo Norte N° 891', 'Chile', 'Metropolitana de Santiago', 'Cordillera', 'Puente Alto', 'Property', 'closed', 'Rotura de cañerías', 'Hubo una filtración en el baño en el segundo piso detrás del lava manos, lo cual generó la salida de agua hacia el primer piso y exterior de la casa, posteriormente se reventaron los codos de la conexión de agua de la cocina quedando al cocina inundada', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Maria Silveria Millao Flores', 'flga.mariajosegonzalez.m@gmail.com', '1962902', 'CHL.215074', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-02-10', '2026-03-10', '2026-03-10');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('801fb898-c2cc-9d63-2037-29413d90c649', 'CHL-00000218', '249565', 'HDI Seguros', 'Comunidad Edificio Pucara', '', '53310943-8', 'Luis_Oyarzun@ajg.com', '', '9 8335 9911', 'Pucara N° 5050', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Ñuñoa', 'Property', 'closed', 'Rotura de cañerías', 'que el día de ayer miércoles 18 de febrero del presente año se comunicó con conserjería el residente del departamento 202, informando que su unidad presenta filtraciones por el área del radiador de calefacción, lo que ha ocasionado daños en distintas zonas del departamento. Al momento de efectuarse el reclamo, se contactó a un técnico para realizar la revisión correspondiente, pudiendo corroborar que el origen del problema se debe a una válvula (llave) que se encontraba filtrando. Esta misma filtración también provocó daños en el techo de la conserjería.', 'NO', 'NO', 'N/A', 'ARTHUR J. GALLAGHER CORREDORES DE SEGUROS SPA', '', '', '', '', 'Comunidad Edificio Pucara', 'Luis_Oyarzun@ajg.com', '1022154', 'CHL.215085', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-02-18', '2026-02-26', '2026-03-10');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('2d4a8f9b-f5c0-6013-262f-525f3e34fbae', 'CHL-00000219', '249567', 'HDI Seguros', 'Comunidad Edificio Pucara', '', '53310943-8', 'Luis_Oyarzun@ajg.com', '', '5 3310 9438', 'Pucara N° 5050 Depto N° 202', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Ñuñoa', 'Property', 'closed', 'Rotura de cañerías', 'que el día de ayer miércoles 18 de febrero del presente año se comunicó con conserjería el residente del departamento 202, informando que su unidad presenta filtraciones por el área del radiador de calefacción, lo que ha ocasionado daños en distintas zonas del departamento. Al momento de efectuarse el reclamo, se contactó a un técnico para realizar la revisión correspondiente, pudiendo corroborar que el origen del problema se debe a una válvula (llave) que se encontraba filtrando. Esta misma filtración también provocó daños en el techo de la conserjería. Dejo constancia de los hechos y adjunto evidencias claras para su consideración, con el fin de gestionar la visita técnica a la brevedad posible.', 'NO', 'NO', 'N/A', 'ARTHUR J. GALLAGHER CORREDORES DE SEGUROS SPA', '', '', '', '', 'Paolo Araya A.', 'paraya@cordova.cl', '1022155', 'CHL.215086', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-02-18', '2026-02-26', '2026-03-10');
