INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('c01d3f7b-9db6-32de-92ac-aa4da0d9ee92', 'CHL-00000233', '20611673', 'HDI Seguros', 'Fabián', 'Aedo Ramírez', '12037995-k', 'aedo.fabian@gmail.com', '', '', 'Los Peumos Sur N° 8191', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Peñalolén', 'Property', 'closed', 'Rotura de cañerías', 'Se ha roto una cañería que pasa por sobre una habitación del primer piso y que surte de agua al baño del segundo piso. Esta rotura ha causado daños al interior de un armario, debiendo reemplazar parte del cielo, las paredes del armario y el piso flotante de la habitación del primer piso. Para poder reparar la cañería se ha debido romper varias tuberías de desague, ya que todas pasan por el mismo lugar. Se ha debido reemplazar un tramo de estas tuberías que resultaron afectadas por la reparación de la cañería rota. La cañería se ha roto porque estaba en contacto con el armazón de la estructura de acero de la casa, lo que hizo que se rompiera, afectando a todo lo que se encontraba debajo, en la habitación del primer piso. Se han dañado además diversos artículos que estaban dentro del armario', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Fabián Aedo Ramírez', 'aedo.fabian@gmail.com', '1963037', 'CHL.215123', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-02-17', '2026-03-11', '2026-03-11');
