INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('e3e59e6f-ca38-1abb-734d-20eefef92c57', 'CHL-00000253', '20611673', 'HDI Seguros', 'Juan Guillermo', 'Vera Vasquez', '9030206-K', 'guilvasq@gmail.com', '', '9 5127 7496', 'Pasaje El Libano Poniente Uno N° 876', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Maipú', 'Property', 'closed', 'Rotura de cañerías', 'Con fecha 04 de marzo de 2026, se detectó visualmente que el medidor de agua del inmueble se encontraba marcando, sin haber consumo aparente en ninguna llave del inmueble. Se tomó contacto con un especialista (gasfiter) quien con fecha 06 de marzo se hizo presente para hacer una evaluación y pruebas de la situación, determinándose que existía una fuga bajo la superficie del piso de la dependencia donde se ubica la cocina del inmueble. Una vez determinado el sector se procedió a intervenir el piso(se rompió el piso de hormigón y cerámica), descubriéndose una fuga en una unión que conecta la cañería principal proveniente del medidor y que alimenta un circuito de distribución interno de la casa, lo que provocaba una gran fuga de agua bajo la superficie. Dicho especialista en los días posteriores procedió a su reparación y a la fecha se encuentra en observación, antes de cubrir nuevamente el sector y reponer la cubierta de cemento y cerámica del sector afectado', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Juan Guillermo Vera Vásquez', 'guilvasq@gmail.com', '1963700', 'CHL.215186', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-03-04', '2026-03-17', '2026-03-18');
