INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('f41cf9e8-d86a-7c68-3f2d-5c13b2cd8ee7', 'CHL-00000277', '20611673', 'HDI Seguros', 'Alejandro Martin', 'Araujo', '22131967-2', 'alejandro.araujo1971@gmail.com', '', '9 6219 3186', 'Avenida Parque Chamisero N° 15900', 'Chile', 'Metropolitana de Santiago', 'Chacabuco', 'Colina', 'Property', 'closed', 'Rotura de cañerías', 'El dormitorio principal tiene baño en suite. El miércoles 18-Mar-2026 por la mañana, al mover una cómoda ubicada frente a la cama, vimos que la pared que separa el baño del doritorio estaba en mal estado, con la pintura englobada en varios lugares, y en el baño (principalmente piso) se ven señales de humedad en el piso (en las juntas entre el porcelanato). Debido a que hay enchufes en ese sector (pared) afectado en el dormitorio, ya hemos contactado a un contratista para que comiencen a trabajar en la detección y resolución del problema', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Alejandro Martin Araujo', 'alejandro.araujo1971@gmail.com', '1964251', 'CHL.215360', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-03-18', '2026-03-23', '2026-03-23');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('a1330914-50bb-8452-70d3-cc6e00da8240', 'CHL-00000278', '20611182', 'HDI Seguros', 'Inversiones Verito', '', '99510370-2', 'contacto@distritocs.cl', '', '9 4278 1114', 'Mar Bravo 8 casa 1', 'Chile', 'Valparaíso', 'Petorca', 'Zapallar', 'Property', 'closed', 'Rotura de cañerías', 'A raíz de un consumo inusualmente elevado de agua potable, se procedió a revisar la red interior del inmueble, detectándose una fuga en el tramo comprendido entre
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('ae0bb360-1aa7-45a7-431c-c267d17cc811', 'CHL-00000279', '251245', 'HDI Seguros', 'Eduardo Dib Y Cia Ltda.', 'zoyarzun@dib.cl', '88610100-7', 'valeria_valencia@ajg.com;', '', '9 8335 9912', 'Juan Soler Manfredini 131 LC Z2 Mall costanera', 'Chile', 'Los Lagos', 'Llanquihue', 'Puerto Montt', 'Property', 'in_review', 'Filtración de aguas lluvias', 'Al ingresar al local, se detectó una inundación que cubría toda el área de exhibición y pasillos con aproximadamente 2 cm de agua. Tras inspeccionar la bodega y encender la iluminación, se confirmó que el agua se había extendido por todo el recinto, afectando críticamente la zona de almacenamiento de mercadería. A pesar de las labores inmediatas de extracción y secado, la porosidad del suelo mantuvo niveles altos de humedad residual durante varios días. Cabe señalar que otros locales del centro comercial presentaron el mismo inconveniente, sin que hasta la fecha se haya informado el origen exacto de la filtración', 'NO', 'NO', 'N/A', 'ARTHUR J. GALLAGHER CORREDORES DE SEGUROS SPA', '', '', '', '', 'Eduardo Dib Y Cia Ltda.', 'valeria_valencia@ajg.com', '1022170', 'CHL.215375', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-02-17', '2026-03-19', '2026-03-23');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('df4c9a15-33ed-6384-e4c2-102d86fcfce5', 'CHL-00000280', '249907', 'HDI Seguros', 'Condominio Alto Castaño Dos', '', '65128447-3', 'angy.henriquez73@gmail.com', '', '9 7600 7274', 'Pinares N° 24', 'Chile', 'Biobío', 'Concepción', 'Chiguayante', 'Property', 'closed', 'Daños por Vehículos', 'Fecha 14/03/26 Lugar condominio alto castaño 2 Impacto
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('79b59cfa-ac3e-60d8-453b-f179173ad786', 'CHL-00000281', '20623953', 'HDI Seguros', 'Erick Byron', 'Bracamonte Garcia', '9.687.939-3', 'ebracamonte@in3.cl', '', '9 7709 1314', 'Arturo Fernandez 2098  N° 1107', 'Chile', 'Tarapacá', 'Iquique', 'Iquique', 'Property', 'closed', 'Rotura de cañerías', 'Por medio del presente, informo los hechos ocurridos en mi departamento N° 1107, relacionados con un incidente por filtración de agua originado en el área de la cocina. El incidente se produjo durante la madrugada, cuando recibí un aviso de conserjería indicando que vecinos estaban alertando sobre el ingreso de agua a sus departamentos y que esta provenía desde mi unidad. A raíz de ello, al revisar la situación, me percaté de que en mi departamento había una importante acumulación de agua en el piso y pude constatar que la filtración provenía de la rotura de la cañería ubicada bajo el lavaplatos. Como consecuencia del volumen de agua liberado y del tiempo de exposición, el agua se desplazó horizontalmente hacia los departamentos colindantes, correspondientes a las unidades 1106 y 1109. Una vez detectada la situación, procedí de forma inmediata al cierre de la llave de paso general, además de realizar un secado superficial de las áreas comunes y privadas que se vieron comprometidas. En cuanto a los daños ocasionados a terceros, se informa lo siguiente: Departamento 1106 Se registró ingreso de agua por la puerta principal, afectando el revestimiento de piso del departamento. Departamento 1109 Se registró ingreso de agua por la puerta principal, afectando el revestimiento de piso del departamento. Asimismo, se observaron daños en la puerta del clóset del dormitorio y en la puerta de acceso al baño. Todo lo anterior, según consta y respalda informe emitido', 'NO', 'NO', 'N/A', '', '', '', '', '', 'Erick Byron Bracamonte Garcia', 'ebracamonte@in3.cl', '1964389', 'CHL.215380', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-01-21', '2026-03-24', '2026-03-24');
