INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('68c410b3-e028-fa41-1060-46e664d8b58d', 'CHL-00000283', '20611673', 'HDI Seguros', 'Yudi Tamar', 'Figueroa Luarte', '18417884-2', 'yufigueroa1993@gmail.com', '', '9 7677 8278', 'Calle Manquimavida Torre N° A 600 Depto 10', 'Chile', 'Biobío', 'Concepción', 'Chiguayante', 'Property', 'closed', 'Rotura de cañerías', 'Posible fuga de agua derivada de cañería de baño visitas, nos percatamos de que el medidor estaba girando sin estar ocupando agua por lo que solicitamos asistencia de gasfiter, para detección de fuga y reparación oportuna.', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Yudi Tamar Figueroa Luarte', 'yufigueroa1993@gmail.com', '1964401', '', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-03-20', '2026-03-24', '2026-03-24');
