INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('30350481-9cc2-1699-31d5-e752a5e4b54b', 'CHL-00000312', '20622663', 'HDI Seguros', 'Maria De La Luz', 'Zilleruelo Petre', '5511212-6', 'jfrauenberg@vtr.net', '', '9 8293 8584', 'Av. Bosques De Montemar  N° 400 Depto N° 112', 'Chile', 'Valparaíso', 'Valparaíso', 'Concón', 'Property', 'closed', 'Rotura de cañerías', 'Siniestro por filtración de agua, a mi vecino del departamento del piso inferior. Departamento 102 de Don Carlos Simon,en enero de este año. El desagüe de los lavaplatos de la cocina, lavalozas y lavarropa, descarga por un shaft horizontal en mi cocina, que baja al cielo del depto 102 y ahí horizontalmente al desagüe vertical común a todos los departamentos. Cuando se produjo la filtración, la conserjería del edifico llamo a una empresa que se dedica a destapar estos ductos con máquinas especiales y ellos destaparon el desagüe, y según lo informado por la administración ahora en marzo, el ducto responsable de la filtración corresponde a mi departamento.', 'NO', 'NO', 'N/A', '', '', '', '', '', 'Maria De La Luz Zilleruelo Petre', 'jfrauenberg@vtr.net', '1965339', 'CHL.215606', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-01-10', '2026-04-06', '2026-04-06');
