INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('a5b3ff46-7a02-beb5-336f-c975d0fb43e5', 'CHL-00000358', '20611673', 'HDI Seguros', 'Marco Antonio', 'De La Cerda Flores', '10029409-5', 'mardelacerda@yahoo.com.ar', '', '9 7858 7962', 'Calle El Algarrobos N° 36', 'Chile', 'Metropolitana de Santiago', 'Chacabuco', 'Colina', 'Property', 'closed', 'Rotura de cañerías', 'Fuga de agua en la cañería del agua fría del lavadero. Rotura del codo donde se conecta la llave.;', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Marco Antonio De La Cerda Flores', 'mardelacerda@yahoo.com.ar', '1966602', 'CHL.215724', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-04-10', '2026-04-16', '2026-04-16');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('bd111160-e4ff-dde9-9708-591738f8bbc6', 'CHL-00000359', '20611673', 'HDI Seguros', 'Cristian German', 'Jara Moran', '16429725-K', 'cjmoran09@hotmail.com', '', '9 8276 1408', 'Pasaje La Ronda N° 1188', 'Chile', 'Metropolitana de Santiago', 'Maipo', 'San Bernardo', 'Property', 'closed', 'Rotura de cañerías', 'Con fecha 10 de abril, se detectó una fuga de agua en el piso del baño de visitas, ante esta situación, se procedió a contactar a un gasfíter de forma urgente, quien realizó una inspección técnica utilizando equipo especializado para detectar el origen de la filtración. Se determinó que existía una rotura de cañería de agua potable (material PPR) ubicada bajo el piso en el sector de la cocina, correspondiente a la matriz de alimentación. Debido a que la tubería se encontraba embutida bajo el radier, fue necesario realizar excavación y demolición parcial del piso para acceder al punto dañado. El profesional procedió a retirar el tramo de cañería afectado y reemplazarlo por uno nuevo, solucionando la fuga. La filtración provocó acumulación de agua bajo el pavimento, daños en el sector intervenido, se tuvo que demoler parte del baño, cocina y patio exterior. Esperando su comprensión, le saluda. Cristian Jara.;', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Cristian German Jara Moran', 'cjmoran09@hotmail.com', '1966604', 'CHL.215725', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-04-10', '2026-04-16', '2026-04-16');
