INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('40aa0f34-e900-8a83-9f88-586873354a1e', 'CHL-00000373', '20611673', 'HDI Seguros', 'Ameris S A', '', '76027974-9', 'raparicio@mq.cl', '', '9 7960 0700', 'Avenida General Mackenna N° 1555 Depto. N°  202', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Santiago', 'Property', 'closed', 'Rotura de cañerías', 'En noviembre de 2025, el arrendatario del depto. 2409B informó una filtración que afectaba el baño de su unidad y que provenía del depto. superior 2509B. - En dicha etapa inicial se pagó una visita o revisión técnica, respaldada por la factura electrónica N.° 369, de fecha 17 de noviembre de 2025, por un total de $47.175. - Con fecha 11 de marzo de 2026, la empresa Fugas Pro Spa realizó inspección termográfica e informó que la filtración provenía de la red de agua caliente del depto. 2509B, específicamente en el sector de las llaves de paso del baño, coincidiendo con el punto de goteo observado en el depto. 2409B. - El informe técnico indicó además que la llave de paso general de agua caliente se encontraba en mal estado y recomendó su reemplazo para poder aislar correctamente la red durante la reparación. - La detección termográfica quedó respaldada con la factura electrónica N.° 1060, de fecha 11 de marzo de 2026, por concepto de detección de fuga de agua, por un total de $169.800 IVA incluido. - Posteriormente se emitió el presupuesto N.° 07122-2, de fecha 23 de marzo de 2026, por $485.000 más IVA, correspondiente a una etapa inicial de reparación y terminaciones. Actualmente dichos trabajos se encuentran en ejecución. - Luego se emitió el presupuesto N.° 07122-3, de fecha 28 de marzo de 2026, por $1.485.000 más IVA, que amplía el alcance de las reparaciones por los daños ocasionados por la fuga. Este último presupuesto es el presupuesto vigente principal y comprende el valor de $485.000 más IVA antes indicado, por lo que ese monto no debe considerarse adicional ni separadamente', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Ameris S A', 'raparicio@mq.cl', '1966854', 'CHL.215818', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2025-11-17', '2026-04-20', '2026-04-20');
