INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('a08d0571-5a97-43b0-fe40-b44aa5a22a82', 'CHL-00000391', '20611673', 'HDI Seguros', 'Francisca Lucía', 'Sanzana Pavez', '14165839-5', 'fsanzana@gmail.com', '', '9 9199 9875', 'Pedro Fontova n° 8026 casa N° 3', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Huechuraba', 'Property', 'closed', 'Rotura de cañerías', 'Con fecha 16 de abril, la empresa Aguas Andinas informó la realización de trabajos de reparación en el sector, lo que implicó la suspensión temporal del suministro de agua potable. Una vez restituido el servicio, el agua retornó con una presión significativamente elevada, lo que provocó la rotura de la matriz de agua fría ubicada en las cercanías del medidor (específicamente, un codo de PVC de 40 mm). Como consecuencia de esta situación, se produjo una filtración de agua hacia la superficie. Para poder identificar el punto exacto de la fuga y efectuar la reparación correspondiente, fue necesario intervenir y romper el pavimento del área afectada. Producto de lo anterior, se generaron los siguientes daños y pérdidas materiales: Daño en matriz de agua fría (codo PVC 40 mm y tramo de tubería afectada). Daño en pavimento exterior intervenido para acceder a la fuga. Costos asociados a mano de obra para detección, excavación y reparación de la filtración. El monto estimado total de los daños asciende a $250.000 CLP, el cual podrá ser respaldado conforme a presupuesto y/o pagos emitidos', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Francisca Lucía Sanzana Pavez', 'fsanzana@gmail.com', '1967385', 'CHL.215884', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-04-17', '2026-04-27', '2026-04-27');
