INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('c3fad9bc-c63b-51a3-ffc1-8f5d8337a284', 'CHL-00000400', '20614294', 'HDI Seguros', 'Claudia De Lourdes', 'Hernandez Aguirre', '10592572-7', 'chernandez1967@gmail.com', '', '9 8829 3903', 'El Rosario  N° 4370', 'Chile', 'Coquimbo', 'Elqui', 'Coquimbo', 'Property', 'closed', 'Rotura de cañerías', 'Estando en la casa nos percatamos de ruido parecido a una llave de agua abierta pero no habia ninguna en uso, salimos al patio y escuchamos que el medidor de agua corría en forma desmedida aunque no habia llaves de agua abiertas en la casa (interior ni exterior) se observan distintos sectores de la casa con daños por agua', 'NO', 'NO', 'n/a', '', '', '', '', '', 'Claudia De Lourdes Hernandez Aguirre', 'chernandez1967@gmail.com', '1967502', 'CHL.215933', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-04-19', '2026-04-28', '2026-04-28');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('7d9626b7-6c6d-994a-82d7-90f100863d2a', 'CHL-00000401', '20611673', 'HDI Seguros', 'Pablo Andres', 'Quiroz Llanten', '10931334-3', 'quirozllanten@gmail.com', '', '9 9918 6066', 'Calle Teniente Merino N° 3295', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Maipú', 'Property', 'closed', 'Rotura de cañerías', 'Se tiene una fuga de agua en las cañerias del baño, lo cual genero que las paredes se vieran hinchadas y generando hongos, en conjunto de esto la pintura de la misma se vio afectada además del mismo cielo del baño. Por otro lado también se tienen daños en ventanas de la vivienda en conjunto de la reja perimetral de la misma', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Pablo Andres Quiroz Llanten', 'quirozllanten@gmail.com', '1967620', 'CHL.215947', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-04-09', '2026-04-29', '2026-04-29');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('30323c22-da9a-7e56-a2e4-bacc791fcc7b', 'CHL-00000402', '215478', 'HDI Seguros', 'Marcia Andrea', 'Vega Valdivia', '13534548-2', 'administracion@miaustral.cl', '', '9 6102 8474', 'Av. Pacifico N° 751 Torre Marina Depto N° 412', 'Chile', 'Coquimbo', 'Elqui', 'La Serena', 'Property', 'closed', 'Sismo', 'Se ha tomado conocimiento con fecha 24-04-2026 de este denuncio la ocurrencia de un siniestro por sismo que ha afectado la propiedad provocando danos en estructura muros cielos de los recintos no afectando cobertura de contenido', 'NO', 'NO', 'N/A', '', '', '', '', '', 'Marcia Andrea Vega Valdivia', 'administracion@miaustral.cl', '19008725', 'CHL.215948', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-04-13', '2026-04-24', '2026-04-29');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('3cd82949-bf9b-b8ae-0b04-fb3004b9aa18', 'CHL-00000403', '20626556', 'HDI Seguros', 'Ling', 'Decheng', '21707505-K', 'vling@pansouth.cl', '', '9 8259 1620', 'Guardia Vieja  N° 330 Depto N° 901', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Providencia', 'Property', 'closed', 'Rotura de cañerías', 'El 22/04 nuestro arrendatario del dpto. 901 nos informo que el vecino del piso inferior le dio aviso de una humedad que estaba aflorando en el cielo del baño del dpto. 801, se envio a un contratista a revisar quien repaso sellos de silicona de la llave monomando y se revisaron los desague del receptaculo de la ducha, baño y lavamanos, no encontrandose fuga, sin embargo al ocupar la ducha del dpto. 901 se mantenia el problema de humedad en el baño del dpto. 801, lo que hace pensar que existe una rotura de la cañeria que alimenta la llave monomando de la ducha, se debe romper el muro de ceramico para llegar a estas cañerias y poder reparar o reemplazar lo que este roto', 'NO', 'NO', 'N/A', '', '', '', '', '', 'Ling Decheng', 'vling@pansouth.cl', '1967710', 'CHL.215949', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-04-22', '2026-04-28', '2026-04-29');
