INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('c1ce8798-c9f9-9f22-b698-c120734ef9d6', 'CHL-00000412', '251105', 'HDI Seguros', 'Condominio San Jose De El Abra', '', '65019673-2', 'juanamejias@hotmail.com', '', '9 6676 8832', 'Calle Antofagasta N° 1251', 'Chile', 'Antofagasta', 'Antofagasta', 'Antofagasta', 'Property', 'in_review', 'Rotura de cañerías', 'En el mes de Febrero, una vecina paseando a su perro se da cuenta de un pequeño socavón en la entrada principal del Condominio el Abra, a la altura de la casa 111, la cuál estaba tapada con tierra, pero se evidenciaba un pequeño orificio. Se hace una inspección al sector y a los días cae una llovizna la que tapa con tierra el orificio. Ya en marzo, se evidencia que el socavón empieza a ceder en el terreno, se revisa la tapa de desagüe que está a unos metros para verificar que no sea fuga de aguas servidas, lo cuál no presenta fugas. A mediados de marzo, se solicita la asesoría a maestros de mantención, los cuales señalan que es difícil evidenciar el daño y los costos asociados ya que hay que escarbar el suelo para revisar la magnitud del daño y que debiéramos revisar nuestros seguros. Cada día se nota que el terreno se está curvando. Se envían imágenes del antes y recientes.', 'NO', 'NO', 'N/A', '', '', '', '', '', 'Condominio San Jose De El Abra', 'juanamejias@hotmail.com', '1022255', 'CHL.216017', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-04-19', '2026-04-29', '2026-05-03');
