INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('135bef7a-2b4c-e3ba-46a4-d4a41459d01b', 'CHL-00000416', '258883', 'HDI Seguros', 'Banco de Chile', '', '97004000-5', 'victoria@errazurizcorredores.cl', '', '1 1111 1111', 'Paseo Ahumada 251', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Santiago', 'Property', 'in_review', 'Daños Eléctricos', 'Estamos instalando una planta fotovoltaica y el día viernes realizaron la conexión para que las casas se alimentaran de la energía solar de la planta. El día sábado pude constatar que muchos artefactos no encendían, al parecer se quemaron. No sabemos aún el motivo ni contamos con la información de la empresa que realizó tanto la instalación de la planta con sus placas solares como la conexión misma. • 6 parlantes SONOS ONE, que están distribuidos en living, salita y comedor de quincho • 2 cálifont • 2 ventiladores en quincho • 2 estufas de pared de techo en quincho • 1 estufa central de gas con partidor eléctrico • 1 estufa pared baño dormitorio principal • 1 estufa pared comedor quincho • 1 ventilador terraza dormitorios • 1 motor eléctrico del portón 1.- impresora, 2.- 1 dvr para las cámaras de vigilancia 3.- 2 adaptadores TV y cámaras 4.- 1 robot limpia piscina marca DOLPHIN LIBERTAD 400Ss solicitamos un informe técnico a un ingeniero eléctrico que lo tendremos en los próximos días.', 'NO', 'NO', 'n/a', 'Errazuriz & Cia. Corred. de Seguros Spa.', '', '', '', '', 'Alfredo Montes', 'victoria@errazurizcorredores.cl', '58008217', 'CHL.216029', false, '745762e5-52ef-c237-75