INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('788d7c07-4d19-39a8-6fd6-3d1e7c5d46e1', 'CHL-00000431', '20611673', 'HDI Seguros', 'Emilio Enrique', 'Sanchez Albornoz', '14122681-9', 'emiliosancheza@outlook.com', '', '9 9001 2000', 'Calle Carrion N°1319 Depto. N° 703 Torre B', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Independencia', 'Property', 'closed', 'Rotura de cañerías', 'De acuerdo a la inspección, el siniestro se origina por una fuga en la red de alimentación de en el baño del dormitorio principal. Esta acción directa del agua ha causado daños inmediatos en mi departamento, afectando el piso y otras zonas de la estructura, junto con daños en techo y pisos del departamento del piso inferior (603). La fuga ya se encuentra reparada.;', 'NO', 'NO', 'n/a', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Emilio Enrique Sanchez Albornoz', 'emiliosancheza@outlook.com', '1968386', 'CHL.216118', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-04-13', '2026-05-07', '2026-05-08');
