INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('2c7dd799-6417-b89f-850c-661ae37c81fd', 'CHL-00000433', '213953', 'HDI Seguros', 'Ana Ximena', 'Retamal Carrillo', '12330305-9', 'xretamalc@gmail.com', '', '9 9367 3063', 'La Leñadura N° 646, Lomas De Villa Agueda', 'Chile', 'Magallanes y de la Antártica Chilena', 'Magallanes', 'Punta Arenas', 'Property', 'closed', 'Rotura de cañerías', 'El domingo 27 de abril a las 11:51 horas detecté una falla catastrófica en el sistema de calefacción de mi casa en Punta Arenas. El sistema dejó de funcionar en gran parte, sólo dando un mínimo de calor. La vivienda está fría hasta el punto de ser imposible habitarla, no es un problema de confort, es una condición de inhabitabilidad real y documentable considerando las condiciones climáticas de Punta Arenas en esta época del año..
