INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('3e233438-119c-7499-0ef9-4d6abd6f96f3', 'CHL-00000436', '250386', 'HDI Seguros', 'Comunidad Edificio Agustin Del Castillo', '', '53306030-7', 'c.bastias@casgroupp.cl', '', '9 9541 6789', 'Agustín Del Castillo  N° 2841 B', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Vitacura', 'Property', 'in_review', 'Rotura de cañerías', 'Con fecha 24de Abril del presente año, se produjo un rebalse de aguas servidas proveniente de la vertical sanitaria del edificio, situación que afectó al departamento 202-B y generó daños por inundación en piso flotante y otras terminaciones interiores. De acuerdo con los antecedentes preliminares, el evento tendría origen en una obstrucción asociada al sistema sanitario común, provocando daños a terceros derivados del funcionamiento de las instalaciones del inmueble. En virtud de lo anterior, se solicita evaluación del caso bajo las coberturas de Responsabilidad Civil y daños materiales contempladas en la póliza vigente, quedando pendiente la determinación técnica definitiva del origen específico de la obstrucción y el alcance total de los daños', 'NO', 'NO', 'N/A', '', '', '', '', '', 'Comunidad Edificio Agustin Del Castillo', 'c.bastias@casgroupp.cl', '1022265', 'CHL.216179', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-04-24', '2026-05-08', '2026-05-11');
