INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('ce551cf5-e60d-0f0d-8306-e2fc681fbbe5', 'CHL-00000439', '20611673', 'HDI Seguros', 'Jose Alberto', 'Sanchez Valenzuela', '9934655-8', 'jsanchez@iceal.cl', '', '9 9837 3522', 'Calle Nahuelcura Lt 2b 65', 'Chile', 'Biobío', 'Concepción', 'Chiguayante', 'Property', 'scheduled', 'Rotura de cañerías', 'En el último tiempo habíamos sentido gran olor y presencia de humedad en el segundo piso de nuestra casa, el viernes 08.05.26, al prender la calefacción central, empezó a aflorar agua desde uno de los dos baños del segundo piso, dado esto solicitamos a un técnico que revisara el sistema encontrando una fuga de agua de la red de cañerías al interior de la pared del muro, en la misma instancia solicitamos revisara el resto de las instalaciones por la fuerte presencia de humedad, el técnico retiro parte del piso y pared exterior de uno de los baños identificando además una fuga de agua servida (por el olor) que se propaga por todo el piso del segundo nivel, lo que permite concluir que existe además una fuga de agua del desagüe de uno de los baños (todas las conexiones están entre paredes por lo que no es posible identificar el lugar exacto), se destaca que el daño al piso es generalizado. ;', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Jose Alberto Sanchez Valenzuela', 'jsanchez@iceal.cl', '1968538', 'CHL.216182', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-08', '2026-05-11', '2026-05-12');
