INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('dfca96ec-177a-2bcb-9f0e-c7e9a4ba197b', 'CHL-00000446', '20639643', 'HDI Seguros', 'Inversiones Rt Spa', '', '76710851-6', 'renatotraversor@gmail.com', '', '9 7987 4355', 'Avenida Blanca Estela N° 1055 Depto N° 432', 'Chile', 'Valparaíso', 'Valparaíso', 'Viña del Mar', 'Property', 'in_review', 'Rotura de cañerías', 'Daños propios por fuga de agua en Dpto 432 y por el derrame al piso de abajo el dpto 422 del condominio Prados De Montemar Av Blanca estela 1055 Concón. Luego de ausentarnos algunos días en un viaje realizado nos percatamos al volver que algunos puntos de la habitación de servicio presentaba daños en el piso flotante y humedad en las paredes. Junto con ello las paredes de la pieza de estr presentaban daños por humedad algunos centímetros sobre el piso. pasados los días los daños fueron aumentando, cuando recibimos el aviso de nuestros vecinos de abajo, el 422, que estaban presentando humedad en el techo de su sala de estar y de los pasillos además de parte de la pieza de servicios. Por tal motivo se contrató los servicios de un experto en detecciones de fugas que luego de varios estudios y sondeos, determinó una fuga en nuestro baño de servicios. Estos trabajos, significaron la rotura del shaft de la pieza de servicio que presentaba humedad instrumental en la parte superior ( techo, y pared) y la rotura de la pared, despeje de lavamano y ducha y además de la desinstalación del piso flotante de la pieza de estar. detectandose la fuga nuestra en dicho lugar, procediéndose a la reparación de la misma', 'NO', 'NO', 'N/A', '', '', '', '', '', 'Inversiones Rt Spa', 'renatotraversor@gmail.com', '1968686', 'CHL.216207', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-06', '2026-05-12', '2026-05-13');
