INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('f2eb6bd1-f8c5-14c5-6ebd-4ed222df9e32', 'CHL-00000484', '257612', 'HDI Seguros', 'Comunidad Edificio Los Leones', '', '53302727-K', 'rolguin@admigreen.cl', '', '9 3496 3729', 'Los Leones N° 1615', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Providencia', 'Property', 'in_review', 'Rotura de cañerías', 'Siniestro ocurrido en: Condominio Los Leones 1615, Unidad 201 Por medio de la presente, presento de manera formal la denuncia del siniestro que afectó a la propiedad asegurada ubicada en Condominio Los Leones 1615, Departamento 201, ocurrido el pasado sábado 23 de mayo de 2026, durante el transcurso del día. 1. Descripción del Siniestro De manera imprevista y accidental, se produjo una obstrucción en la vertical de aguas servidas del edificio (matriz común de la copropiedad). Este colapso del sistema provocó el retorno y rebalse de las aguas, generando una severa inundación en el interior de la unidad 201. 2. Detalle Preliminar de los Daños El agua se extendió de manera generalizada por el inmueble, resultando afectados los siguientes componentes: Piso: Daño total por absorción de agua y humedad en toda la superficie del departamento. Puertas: Deformación, hinchazón y daño estructural en marcos y hojas de madera. Guardapolvos: Desprendimiento, pudrición y deterioro completo en las zonas afectadas. 3. Solicitud Dado que el origen del evento corresponde a una causa accidental y externa a la unidad (falla en ducto comunitario),', 'NO', 'NO', 'n/a', '', '', '', '', '', 'Comunidad Edificio Los Leones', 'rolguin@admigreen.cl', '1022297', 'CHL.216497', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-23', '2026-05-26', '2026-05-27');
