INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('8c0b4395-c6af-b2f2-54b4-854926b1b227', 'CHL-00000488', '20595017', 'HDI Seguros', 'Comercial Kaufmann S.A.', '', '96572360-9', 'jackelin.quispe@kaufmann.cl', '', '9 7244 9902', 'Av Gladys Marin Millie N° 5830', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Estación Central', 'Property', 'in_review', 'Robo con Fuerza en las cosas', 'Patrullero alerta por vía radial de intrusión y vulneración en el sector costado calle diagonal de acceso, costado con La Siembra, cortaron un paño completo de cierre perimetral, se toma contacto con personal de carabineros quienes acuden al llamado apersonándose a las 00:13 HRS, me entrevisto con el Sr. Diego Yáñez, cabo primero de dotación de la 59 comisaria de Lampa, acudimos al sector afectado rondando el lugar y se puede apreciar sustracción de neumáticos, sin embargo, se desconoce la cantidad de los mismos, consiguientemente él mismo acoge la denuncia de mi parte y del Sr Rodrigo Llanqui quienes se retiran de la instalación a las 01:00 HRS de la madrugada. El patrullero queda apostado en el lugar junto a un guardia más para apoyarse mutuamente, así el resto del personal de seguridad se mantiene atento y vigilante ante cualquier situación similar. Se reportó y coordinó protocolos con nuestra jefatura directa, Sres. Alberto Román y Hugo Bergmann respectivamente', 'NO', 'NO', 'N/A', '', '', '', '', '', 'Comercial Kaufmann S.A.', 'jackelin.quispe@kaufmann.cl', '1970296', 'CHL.216501', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-22', '2026-05-28', '2026-05-28');
