INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('d998375b-9755-9c57-65ba-10a51f874e6a', 'CHL-00000490', '20623406', 'HDI Seguros', 'Francisco', 'Bobadilla Orellana', '17344691-8', 'fco.bobadilla.o@gmail.com', '', '9 9969 7471', 'Quinta Junge N° 169', 'Chile', 'Biobío', 'Concepción', 'Concepción', 'Property', 'in_review', 'Rotura de cañerías', 'Comenzó a caer una gotera por el borde de un foco de la cocina, por lo cual llame una empresa a que me repara la filtración, lamentablemente al picar se dieron cuenta que el origen no era cerca de donde salía la gotera, si no mas bien solo el punto donde salía el agua, ahora viéndose en la obligación de picar baño del segundo piso para identificar filtración.', 'NO', 'NO', 'N/A', 'Corredores de Seguros Angelica Cid Y Compania Limitada', '', '', '', '', 'Francisco Bobadilla Orellana', 'fco.bobadilla.o@gmail.com', '1970295', 'CHL.216503', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-25', '2026-05-27', '2026-05-28');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('7c139804-53f0-688e-c1f4-7dd944cc3eb8', 'CHL-00000491', '20611673', 'HDI Seguros', 'Victor Guillermo', 'Rios Solis', '13717808-7', 'mquinones@asesoriasasesur.com', '', '9 4292 3722', 'Calle Pucalquin. Barrio Los Pinares N° 144', 'Chile', 'Libertador General Bernardo O''Higgins', 'Cachapoal', 'Rancagua', 'Property', 'in_review', 'Rotura de cañerías', 'Producto de una filtración de rotura de cañerías mi propiedad se vio afectada en varios sectores ;', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Victor Guillermo Rios Solis', 'mquinones@asesoriasasesur.com', '1970404', 'CHL.216504', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-10', '2026-05-27', '2026-05-28');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('e41b204e-0d66-a6f9-8cdf-bc0e7da8129d', 'CHL-00000492', '20611673', 'HDI Seguros', 'Sergio Luis', 'Araya Avalos', '17773102-1', 'sergio.araya.avalos@gmail.com', '', '9 9069 4150', 'Avenida Pacifico N° 2401 Condominio Playa Blanca departamento N°505', 'Chile', 'Coquimbo', 'Elqui', 'La Serena', 'Property', 'closed', 'Rotura de cañerías', 'informo la ocurrencia de un siniestro por fuga de agua en el inmueble ubicado en Avenida Pacífico N° 2401, Condominio Playa Blanca, Departamento 505, piso 5, comuna de La Serena, Región de Coquimbo. Con fecha 22 de mayo de 2025, se detectó una filtración de agua proveniente del sector superior interior del departamento, específicamente sobre la puerta de acceso principal. La fuga fue evidenciada debido a la presencia de humedad y escurrimiento de agua desde el cielo del inmueble, afectando directamente las terminaciones interiores del departamento. Producto de esta situación, se han generado daños visibles en murallas, cielo, pintura y revestimientos interiores, presentándose manchas de humedad, deterioro de pintura, desprendimiento de material y daños en el sector afectado. Asimismo, la humedad ha comprometido la zona cercana al acceso principal del inmueble. A la fecha, el problema no ha sido reparado y la filtración continúa generando deterioro progresivo en las superficies afectadas del departamento. Cabe señalar que, para efectuar la reparación definitiva de la fuga, será necesario realizar trabajos de demolición y remoción de material existente, incluyendo picado y apertura de cielo y/o muros, con el fin de acceder a la cañería afectada y efectuar el reemplazo correspondiente de la tubería dañada. Por lo anterior, solicito la evaluación correspondiente del siniestro y la activación de la cobertura del seguro hipotecario, con el fin de reparar los daños ocasionados por esta filtración de agua y ejecutar las obras necesarias para solucionar el origen del problema. Se adjuntan fotografías como respaldo de los daños detectados en el inmueble', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Sergio Luis Araya Avalos', 'sergio.araya.avalos@gmail.com', '1970410', 'CHL.216505', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-22', '2026-05-27', '2026-05-29');
