INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('453bced5-d4bb-a00a-102a-e2b429905ab3', 'CHL-00000494', '20611673', 'HDI Seguros', 'Salvador Antonio', 'Cabrera Cerro', '16348189-8', 'contacto@acrev.cl', '', '9 6324 5270', 'Calle Provicia De Talca N° 489', 'Chile', 'Maule', 'Talca', 'Maule', 'Property', 'closed', 'Rotura de cañerías', 'Rotura de cañería baño segundo piso reparada desde el exterior', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Salvador Antonio Cabrera Cerro', 'contacto@acrev.cl', '1970418', 'CHL.216507', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-22', '2026-05-27', '2026-05-28');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('68094b9d-665e-daac-e213-86541bcecf79', 'CHL-00000495', '20628159', 'HDI Seguros', 'Jose', 'Gallardo Ule', '14585710-4', 'agspamagallanes@gmail.com', '', '9 9442 1073', 'Mar De Marmara N° 955', 'Chile', 'Magallanes y de la Antártica Chilena', 'Magallanes', 'Punta Arenas', 'Property', 'closed', 'Rotura de cañerías', 'El día 20 de mayo de 2026, en el transcurso del día, en inmueble de mi propiedad ubicado en Calle Mar de Mármara N°955 , actualmente arrendado y habitado permanente por terceros. El siniestro consistió en una rotura de cañería/fuga de agua, la cual provocó daños en revestimientos interiores, afectando principalmente piso y muro del área de living-comedor, así como dormitorio, generando deterioro por humedad y comprometiendo la habitabilidad normal del inmueble. Debido a que la propiedad se encuentra arrendada y habitada permanentemente por el arrendatario, y considerando la necesidad urgente de contener el daño, evitar un mayor deterioro y restituir condiciones mínimas de habitabilidad, fue necesario autorizar el inicio inmediato de las reparaciones de emergencia, no siendo posible postergar la intervención hasta una inspección presencial previa. Por lo anterior, durante el día lunes 25 de mayo de 2026 se procedió a efectuar los trabajos necesarios, incluyendo reparación asociada a la fuga, retiro de material dañado,reparación de áreas afectadas por humedad y reposición de revestimientos afectados, acompañando registro fotográfico del daño observado y del proceso de reparación realizado. Solicito se tenga presente la situación descrita, considerando el carácter urgente de la reparación y la imposibilidad material de postergar las obras sin afectar la habitabilidad del inmueble y sin exponer la propiedad a daños mayores.', 'NO', 'NO', 'n/a', '', '', '', '', '', 'Jose Gallardo Ule', 'agspamagallanes@gmail.com', '1970446', 'CHL.216524', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-20', '2026-05-28', '2026-05-29');
