INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('5458ac18-a6e6-5525-123f-123532a2dd6c', 'CHL-00000504', '12762', 'HDI Seguros', 'Asoc. Chilena De Rad E Imag Veterinaria', '', '65178263-5', 'rosario.ovalle.d@gmail.com', '', '9 8885 8862', 'Avda Italia N° 1045', 'Chile', 'Metropolitana de Santiago', 'Santiago', 'Providencia', 'Property', 'in_review', 'Avería de maquinaria', 'Con fecha miércoles 27 de mayo, sufrí un accidente que afectó mi equipo electrónico de uso veterinario, correspondiente a un ecógrafo marca Esaote, modelo MyLab Sigma. El incidente ocurrió mientras realizaba una evaluación ecográfica a un paciente canino de aproximadamente 25 kg, en presencia de su tutor, dentro de la consulta. El paciente se encontraba posicionado sobre una colchoneta especial en decúbito ventral, utilizada para facilitar una evaluación completa durante el examen. Durante el procedimiento, el paciente se mostró inquieto. Al finalizar la evaluación, mientras junto al tutor intentábamos reincorporarlo a su posición normal, el canino realizó un movimiento brusco, golpeando con una de sus extremidades la pantalla del ecógrafo. Producto del impacto, se quebró una de las esquinas de la base de la pantalla del equipo. Posteriormente, posicionamos al paciente en el suelo y procedimos a revisar los daños del equipo. En ese momento, el paciente comenzó a morder el cable cargador del ecógrafo, provocando también daños y ruptura de dicho accesorio. Los daños ocasionados afectan tanto la estructura de la pantalla del equipo como el cable cargador correspondiente.', 'NO', 'NO', 'N/A', '', '', '', '', '', 'Asoc. Chilena De Rad E Imag Veterinaria', 'rosario.ovalle.d@gmail.com', '22003290', 'CHL.216533', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-27', '2026-05-28', '2026-05-29');
