INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('fe7d6d43-5b43-eb96-36c8-b379714c0740', 'CHL-00000513', '20619645', 'HDI Seguros', 'Julio', 'Chacon Roa', '8282210-0', 'jacr1960@hotmail.com', '', '9 6365 8773', 'Los Canelos N° 391 Casa A', 'Chile', 'Valparaíso', 'San Antonio', 'Santo Domingo', 'Property', 'in_review', 'Rotura de cañerías', 'Tal como indica cliente en un wasp, tuvo un siniestro de gas en la face del estanque a la casa ( gasco ) me indica que: por medio de la presente vengo a informar y efectuar denuncia de siniestro asociado a una fuga de gas detectada en la propiedad asegurada ubicada en los canelos 391 casa a sto domingo póliza 20538398. La situación genero riesgo para la vivienda y sus ocupantes requiriendo intervención técnica urgente , revisión de instalaciones y trabajos de reparación asociados a la red afectada. La fuga detectada implico riesgo potencial de explosión y necesidad inmediata de reparación incluyendo revisión de cañerías, posibles trabajos de excavación , desmontajes y daños asociados derivados del siniestro', 'NO', 'NO', 'n/a', '', '', '', '', '', 'Julio Chacon Roa', 'jacr1960@hotmail.com', '1970763', 'CHL.216599', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-14', '2026-06-02', '2026-06-02');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('140be63d-8bf1-6120-6366-7629313ca5e7', 'CHL-00000514', '20611673', 'HDI Seguros', 'Bárbara Andrea', 'Flores Fuentes', '17755591-6', 'barbarafloresfuentes@gmail.com', '', '9 3312 1057', 'Avenida Las Rosas N° 1679', 'Chile', 'Biobío', 'Concepción', 'San Pedro de la Paz', 'Property', 'in_review', 'Rotura de cañerías', 'Quiero denunciar un siniestro asociado a una filtración de agua detectada posterior al sismo ocurrido el día sábado 9 de mayo en Concepción. La fuga está generando daños en el interior del departamento sobre todo en el piso del pasillo al lado del baño de donde se supone estaría la fuga además de filtración hacia el departamento del piso inferior generando daños en su techo. No existían antecedentes previos de esta fuga antes del evento sísmico. ;', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', '', '', '1970762', 'CHL.216600', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-25', '2026-06-01', '2026-06-02');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('4093da5c-300f-328a-a1d8-1d74c8dfeb34', 'CHL-00000515', '20611673', 'HDI Seguros', 'Pavel', 'Meneses Vila', '12449904-6', 'pavel.menesesv@gmail.com', '', '9 4299 1514', 'Pasaje Bailarin N° 2653', 'Chile', 'Valparaíso', 'Marga Marga', 'Quilpué', 'Property', 'in_review', 'Viento y Lluvia', 'Con fecha 6 de mayo de 2026, a raíz de las precipitaciones registradas, mi vivienda presentó filtraciones de agua en el sector de unión entre la chimenea y la techumbre. Esta situación permitió el ingreso de agua lluvia, provocando daños en la estructura del techo y en los materiales que conforman la techumbre. Asimismo, la filtración se extendió hacia el primer piso de la vivienda a través de la misma chimenea, generando escurrimiento de agua al interior del inmueble', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Pavel Meneses Vila', 'pavel.menesesv@gmail.com', '1970775', 'CHL.216601', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-06', '2026-06-01', '2026-06-02');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('1e2eb7b8-d520-0480-d772-0ea13a7334b0', 'CHL-00000516', '20611673', 'HDI Seguros', 'Pavel', 'Meneses Vila', '12449904-6', 'pmeneses@cavco.cl', '', '9 4299 1514', 'Pasaje Bailarin N° 2653', 'Chile', 'Valparaíso', 'Marga Marga', 'Quilpué', 'Property', 'in_review', 'Rotura de cañerías', 'Tenemos una filtración de agua proveniente de la tina de baño ubicada en el segundo piso de la vivienda. La filtración se produce durante el uso habitual de la tina, observándose el escurrimiento de agua desde el tubing hacia el primer piso', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Pavel Meneses Vila', 'pmeneses@cavco.cl', '1970776', 'CHL.216602', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-21', '2026-06-01', '2026-06-02');
