INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('f537abab-781d-8538-ba3f-8e708306757a', 'CHL-00000524', '20611673', 'HDI Seguros', 'Nancy Romina', 'Gonzalez Neira', '13506631-1', 'romina.gonzalezn@gmail.com', '', '9 9228 3464', 'Avenida Torreones Oeste N° 1772 Casa N° 25', 'Chile', 'Biobío', 'Concepción', 'Concepción', 'Property', 'in_review', 'Rotura de cañerías', 'Cerca de las 22:00 horas empieza a caer a chorros agua desde el cañón de la estufa en e primer piso y en el segundo piso también. Abarcando inundaciones en el pasillo y baño del primer piso. Además del pasillo y los dormitorios, 2 baños, y walking closet del segundo piso. No sabemos el origen de la filtración de agua', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Nancy Romina Gonzalez Neira', 'romina.gonzalezn@gmail.com', '1970857', 'CHL.216640', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-06-01', '2026-06-02', '2026-06-03');
INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('a0919ec0-2e26-d5ab-673e-0ba8335acdfe', 'CHL-00000525', '20611673', 'HDI Seguros', 'Lesly Tamara', 'Vidal Irrazabal', '16254514-0', 'rusqueraineri.asesorias@gmail.com', '', '9 6706 7248', 'Calle Toribio Valdivia Reyes Casa N°33', 'Chile', 'Libertador General Bernardo O''Higgins', 'Cachapoal', 'Machalí', 'Property', 'in_review', 'Rotura de cañerías', 'Nos dimos cuenta que nuevamente nuestro medidor volvió a girar, cortamos todas las llaves y seguía girando, llamamos al mismo gasfiter de la vez anterior y nos ha detectado la fuga en la logia, bajo el radier. Las cerámicas ya no existen en diseño y color, no queremos tener un parche de color distinto en el piso de cerámicas. La rotura de cañerías era grande.;', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Lesly Tamara Vidal Irrazabal', 'rusqueraineri.asesorias@gmail.com', '1970861', 'CHL.216641', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-15', '2026-06-02', '2026-06-03');
