INSERT INTO claims (id, claim_number, policy_number, insurance_company, insured_name, last_name, rut, insured_email, insured_phone, cell_phone, address, country, region, city, commune, claim_type, status, claim_cause, summary, recovery_type_legal, recovery_type_material, recovery_comments, broker_name, broker_executive, broker_number, builder_name, advisor, contact_name, contact_email, company_report_number, client_reference, is_special_claim, company_id, claim_date, report_date, assignment_date) VALUES ('8572321c-492a-d17f-7b3e-a000748dd83f', 'CHL-00000534', '20611673', 'HDI Seguros', 'Jhonathan Isaac', 'Morgado Seura', '17436965-8', 'j.morgadoseura@gmail.com', '', '9 9472 5423', 'Avenida Rica Aventura N° 11930 Depto N° J-41', 'Chile', 'Antofagasta', 'Antofagasta', 'Antofagasta', 'Property', 'in_review', 'Rotura de cañerías', 'Me he percatado de que hay una fuga de agua en las cañerías internas de ambos baños de mi departamento, el agua se ha comenzado a filtrar por las paredes humedeciendo el guarda polvo y sectores de la pared del baño. Vivo en el cuarto piso de una torre de 5 pisos, vecinos de pisos inferiores informan que el agua se le está filtrando por distintas partes, especialmente por la luz de sus baños, esto ha generado cortes de luz en sus departamentos, por lo que he tenido que mantener todo el día y la noche la llave de paso cerrada de mi dpto. Desconozco si el origen fue por el último sismo que ocurrió pero posterior a eso se ha hecho más grave el problema. He logrado gestionar con un gasfiter que trabaja con factura para que realice la reparación pero recién tengo hora para el 13 de junio del presente, que es cuando vendrán a romper el muro del baño, localizar la filtración y proceder a su reparación. Me preocupa la situación de mis vecinos y si es posible cubrir sus daños con este seguro, ya que están teniendo problemas eléctricos a raíz de las filtraciones, lo que podría generar un incendio.', 'NO', 'NO', 'N/A', 'BCI Corredores de Seguros S.A.', '', '', '', '', 'Jhonathan Isaac Morgado Seura', 'j.morgadoseura@gmail.com', '1971056', 'CHL.216674', false, '745762e5-52ef-c237-75ba-b33a509781a6', '2026-05-26', '2026-06-03', '2026-06-04');
